CREATE TYPE "BillingCycle" AS ENUM ('MONTHLY', 'WEEKLY', 'QUARTERLY', 'HALF_YEARLY', 'YEARLY', 'CUSTOM');
CREATE TYPE "ProrationMethod" AS ENUM ('NONE', 'DAILY');
CREATE TYPE "LeaseBillingStatus" AS ENUM ('DRAFT', 'ACTIVE', 'PAUSED', 'COMPLETED', 'ARCHIVED');
CREATE TYPE "RentScheduleStatus" AS ENUM ('SCHEDULED', 'DUE', 'OVERDUE', 'CANCELLED');
CREATE TYPE "RentEscalationType" AS ENUM ('PERCENTAGE', 'FIXED');
CREATE TYPE "LateFeeType" AS ENUM ('FLAT', 'PERCENTAGE');
CREATE TYPE "SecurityDepositStatus" AS ENUM ('NOT_REQUIRED', 'PENDING', 'HELD', 'PARTIALLY_REFUNDED', 'REFUNDED');
CREATE TABLE "LeaseBillingCalendar" ("id" TEXT NOT NULL, "leaseId" TEXT NOT NULL, "billingCycle" "BillingCycle" NOT NULL, "customIntervalDays" INTEGER, "dueDaysAfterPeriodStart" INTEGER NOT NULL DEFAULT 0, "prorationMethod" "ProrationMethod" NOT NULL DEFAULT 'DAILY', "status" "LeaseBillingStatus" NOT NULL DEFAULT 'DRAFT', "currency" TEXT NOT NULL DEFAULT 'INR', "schedulesGeneratedThrough" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "deletedAt" TIMESTAMP(3), CONSTRAINT "LeaseBillingCalendar_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseBillingCalendar_custom_cycle_check" CHECK (("billingCycle" = 'CUSTOM' AND "customIntervalDays" IS NOT NULL AND "customIntervalDays" > 0) OR ("billingCycle" <> 'CUSTOM' AND "customIntervalDays" IS NULL)), CONSTRAINT "LeaseBillingCalendar_due_days_check" CHECK ("dueDaysAfterPeriodStart" >= 0));
CREATE TABLE "LeaseRentSchedule" ("id" TEXT NOT NULL, "calendarId" TEXT NOT NULL, "sequence" INTEGER NOT NULL, "periodStartsAt" TIMESTAMP(3) NOT NULL, "periodEndsAt" TIMESTAMP(3) NOT NULL, "dueAt" TIMESTAMP(3) NOT NULL, "rentAmount" DECIMAL(14,2) NOT NULL, "escalationAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "prorationAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "totalDue" DECIMAL(14,2) NOT NULL, "status" "RentScheduleStatus" NOT NULL DEFAULT 'SCHEDULED', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseRentSchedule_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseRentSchedule_dates_check" CHECK ("periodEndsAt" > "periodStartsAt"), CONSTRAINT "LeaseRentSchedule_amounts_check" CHECK ("rentAmount" >= 0 AND "escalationAmount" >= 0 AND "prorationAmount" >= 0 AND "totalDue" >= 0));
CREATE TABLE "LeaseRentEscalationRule" ("id" TEXT NOT NULL, "calendarId" TEXT NOT NULL, "effectiveAt" TIMESTAMP(3) NOT NULL, "type" "RentEscalationType" NOT NULL, "amount" DECIMAL(14,2) NOT NULL, "intervalMonths" INTEGER, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseRentEscalationRule_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseRentEscalationRule_amount_check" CHECK ("amount" >= 0), CONSTRAINT "LeaseRentEscalationRule_interval_check" CHECK ("intervalMonths" IS NULL OR "intervalMonths" > 0));
CREATE TABLE "LeaseLateFeeRule" ("id" TEXT NOT NULL, "calendarId" TEXT NOT NULL, "type" "LateFeeType" NOT NULL, "amount" DECIMAL(14,2) NOT NULL, "gracePeriodDays" INTEGER NOT NULL DEFAULT 0, "maximumAmount" DECIMAL(14,2), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseLateFeeRule_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseLateFeeRule_amount_check" CHECK ("amount" >= 0 AND "gracePeriodDays" >= 0 AND ("maximumAmount" IS NULL OR "maximumAmount" >= 0)));
CREATE TABLE "LeaseSecurityDeposit" ("id" TEXT NOT NULL, "calendarId" TEXT NOT NULL, "requiredAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "heldAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "refundedAmount" DECIMAL(14,2) NOT NULL DEFAULT 0, "status" "SecurityDepositStatus" NOT NULL DEFAULT 'NOT_REQUIRED', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "LeaseSecurityDeposit_pkey" PRIMARY KEY ("id"), CONSTRAINT "LeaseSecurityDeposit_amount_check" CHECK ("requiredAmount" >= 0 AND "heldAmount" >= 0 AND "refundedAmount" >= 0 AND "refundedAmount" <= "heldAmount"));
CREATE UNIQUE INDEX "LeaseBillingCalendar_leaseId_key" ON "LeaseBillingCalendar"("leaseId"); CREATE INDEX "LeaseBillingCalendar_status_deletedAt_idx" ON "LeaseBillingCalendar"("status", "deletedAt"); CREATE UNIQUE INDEX "LeaseRentSchedule_calendarId_sequence_key" ON "LeaseRentSchedule"("calendarId", "sequence"); CREATE UNIQUE INDEX "LeaseRentSchedule_calendarId_periodStartsAt_key" ON "LeaseRentSchedule"("calendarId", "periodStartsAt"); CREATE INDEX "LeaseRentSchedule_calendarId_status_dueAt_idx" ON "LeaseRentSchedule"("calendarId", "status", "dueAt"); CREATE UNIQUE INDEX "LeaseRentEscalationRule_calendarId_effectiveAt_key" ON "LeaseRentEscalationRule"("calendarId", "effectiveAt"); CREATE INDEX "LeaseRentEscalationRule_calendarId_effectiveAt_idx" ON "LeaseRentEscalationRule"("calendarId", "effectiveAt"); CREATE UNIQUE INDEX "LeaseLateFeeRule_calendarId_key" ON "LeaseLateFeeRule"("calendarId"); CREATE UNIQUE INDEX "LeaseSecurityDeposit_calendarId_key" ON "LeaseSecurityDeposit"("calendarId");
ALTER TABLE "LeaseBillingCalendar" ADD CONSTRAINT "LeaseBillingCalendar_leaseId_fkey" FOREIGN KEY ("leaseId") REFERENCES "Lease"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseRentSchedule" ADD CONSTRAINT "LeaseRentSchedule_calendarId_fkey" FOREIGN KEY ("calendarId") REFERENCES "LeaseBillingCalendar"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseRentEscalationRule" ADD CONSTRAINT "LeaseRentEscalationRule_calendarId_fkey" FOREIGN KEY ("calendarId") REFERENCES "LeaseBillingCalendar"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseLateFeeRule" ADD CONSTRAINT "LeaseLateFeeRule_calendarId_fkey" FOREIGN KEY ("calendarId") REFERENCES "LeaseBillingCalendar"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "LeaseSecurityDeposit" ADD CONSTRAINT "LeaseSecurityDeposit_calendarId_fkey" FOREIGN KEY ("calendarId") REFERENCES "LeaseBillingCalendar"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
